import subprocess, os, sys

if not os.path.exists("src/gpt4free/tui"):
    print("ОШИБКА: запустите из папки gpt4free!"); sys.exit(1)

def w(path, data):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    open(path, "wb").write(bytes.fromhex(data))

def c(msg, *paths):
    for p in paths: subprocess.run(["git","add",p], check=True)
    subprocess.run(["git","commit","-q","-m",msg], check=True)
    fname = paths[0].split("/")[-1]
    print("OK (" + fname + "): " + msg)

